import{_ as s,o as t,c as i,a2 as n}from"./chunks/framework.BFVZdVmd.js";const c=JSON.parse('{"title":"JVM","description":"","frontmatter":{},"headers":[],"relativePath":"java-core/jvm.md","filePath":"java-core/jvm.md","lastUpdated":null}'),e={name:"java-core/jvm.md"};function l(p,a,h,r,d,o){return t(),i("div",null,[...a[0]||(a[0]=[n(`<h1 id="jvm" tabindex="-1">JVM <a class="header-anchor" href="#jvm" aria-label="Permalink to &quot;JVM&quot;">​</a></h1><blockquote><p>本页为知识库新增内容，不属于《Spring 技术套件》原文档。</p></blockquote><p>JVM 是 Java 后端绕不开的底层。线上排查内存溢出、GC 停顿、CPU 飙高等问题，都要求理解 JVM 的内存结构和垃圾回收机制。</p><h2 id="运行时内存结构" tabindex="-1">运行时内存结构 <a class="header-anchor" href="#运行时内存结构" aria-label="Permalink to &quot;运行时内存结构&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>JVM 内存</span></span>
<span class="line"><span>├── 堆（Heap）          // 对象实例，GC 主战场，线程共享</span></span>
<span class="line"><span>│   ├── 新生代（Young）  // Eden + S0 + S1</span></span>
<span class="line"><span>│   └── 老年代（Old）</span></span>
<span class="line"><span>├── 方法区/元空间        // 类元信息，JDK 8 后用 Metaspace（本地内存）</span></span>
<span class="line"><span>├── 虚拟机栈（Stack）    // 方法调用的栈帧，线程私有</span></span>
<span class="line"><span>├── 本地方法栈           // native 方法</span></span>
<span class="line"><span>└── 程序计数器           // 当前执行字节码行号，线程私有</span></span></code></pre></div><p>要点：</p><ul><li><strong>堆</strong>是线程共享的，对象基本都分配在这里，也是 GC 的主要区域。</li><li><strong>栈</strong>是线程私有的，每次方法调用创建一个栈帧，存放局部变量、操作数栈。栈深度超限抛 <code>StackOverflowError</code>。</li><li>JDK 8 移除了永久代（PermGen），改用<strong>元空间（Metaspace）</strong>，使用本地内存，类加载过多时可能 <code>Metaspace OOM</code>。</li></ul><h2 id="垃圾回收" tabindex="-1">垃圾回收 <a class="header-anchor" href="#垃圾回收" aria-label="Permalink to &quot;垃圾回收&quot;">​</a></h2><h3 id="对象存活判定" tabindex="-1">对象存活判定 <a class="header-anchor" href="#对象存活判定" aria-label="Permalink to &quot;对象存活判定&quot;">​</a></h3><p>主流用<strong>可达性分析</strong>：从 GC Roots（栈引用、静态变量、常量、JNI 引用等）出发，不可达的对象判定为可回收。</p><h3 id="分代回收" tabindex="-1">分代回收 <a class="header-anchor" href="#分代回收" aria-label="Permalink to &quot;分代回收&quot;">​</a></h3><ul><li>新对象分配在 <strong>Eden</strong>，Minor GC 后存活对象进入 Survivor，多次存活后晋升老年代。</li><li>老年代满触发 <strong>Full GC</strong>，停顿时间长，应尽量避免频繁 Full GC。</li></ul><h3 id="常见垃圾回收器" tabindex="-1">常见垃圾回收器 <a class="header-anchor" href="#常见垃圾回收器" aria-label="Permalink to &quot;常见垃圾回收器&quot;">​</a></h3><table tabindex="0"><thead><tr><th>回收器</th><th>特点</th><th>适用</th></tr></thead><tbody><tr><td>Parallel</td><td>吞吐量优先</td><td>批处理、后台计算</td></tr><tr><td>CMS</td><td>低停顿（已废弃）</td><td>老项目</td></tr><tr><td><strong>G1</strong></td><td>分区回收，可控停顿，JDK 9+ 默认</td><td>大多数服务端应用</td></tr><tr><td><strong>ZGC</strong></td><td>超低停顿（亚毫秒），大堆</td><td>低延迟、大内存场景</td></tr><tr><td>Shenandoah</td><td>低停顿</td><td>类似 ZGC</td></tr></tbody></table><p>新项目大堆、低延迟场景可关注 <strong>ZGC</strong>；通用场景 <strong>G1</strong> 即可。</p><h2 id="类加载机制" tabindex="-1">类加载机制 <a class="header-anchor" href="#类加载机制" aria-label="Permalink to &quot;类加载机制&quot;">​</a></h2><p>类加载过程：<strong>加载 → 验证 → 准备 → 解析 → 初始化</strong>。</p><p><strong>双亲委派模型</strong>：类加载请求先委派给父加载器，父加载器无法完成才自己加载。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Bootstrap ClassLoader   （核心类库 rt.jar）</span></span>
<span class="line"><span>      ↑</span></span>
<span class="line"><span>Extension ClassLoader    （扩展类库）</span></span>
<span class="line"><span>      ↑</span></span>
<span class="line"><span>Application ClassLoader   （应用 classpath）</span></span></code></pre></div><p>作用：保证核心类（如 <code>java.lang.Object</code>）不被篡改，避免重复加载。Tomcat、热部署、SPI 等场景会打破双亲委派。</p><h2 id="线上问题排查" tabindex="-1">线上问题排查 <a class="header-anchor" href="#线上问题排查" aria-label="Permalink to &quot;线上问题排查&quot;">​</a></h2><p>企业开发最实用的部分——JVM 知识最终要落到排查问题上。</p><h3 id="常见问题与方向" tabindex="-1">常见问题与方向 <a class="header-anchor" href="#常见问题与方向" aria-label="Permalink to &quot;常见问题与方向&quot;">​</a></h3><table tabindex="0"><thead><tr><th>现象</th><th>可能原因</th><th>排查方向</th></tr></thead><tbody><tr><td><code>OutOfMemoryError: Java heap space</code></td><td>内存泄漏、堆太小、大对象</td><td>堆转储分析</td></tr><tr><td><code>OutOfMemoryError: Metaspace</code></td><td>类加载过多、动态代理泄漏</td><td>类加载监控</td></tr><tr><td>Full GC 频繁</td><td>老年代压力大、内存泄漏</td><td>GC 日志分析</td></tr><tr><td>CPU 飙高</td><td>死循环、频繁 GC</td><td>线程栈分析</td></tr></tbody></table><h3 id="常用工具" tabindex="-1">常用工具 <a class="header-anchor" href="#常用工具" aria-label="Permalink to &quot;常用工具&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">jps</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">              # 查看 Java 进程</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">jstat</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -gc</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">pi</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">d</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  # 查看 GC 统计</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">jstack</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">pi</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">d</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">     # 导出线程栈，排查死锁、CPU 高</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">jmap</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -dump:format=b,file=heap.hprof</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">pi</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">d</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">   # 导出堆转储</span></span></code></pre></div><ul><li><strong>堆转储</strong>用 MAT、JProfiler、VisualVM 分析，定位内存泄漏的对象。</li><li><strong>GC 日志</strong>（<code>-Xlog:gc*</code>）分析停顿时间和频率。</li><li>生产环境推荐接入 <a href="/my-docs/observability/">可观测性</a>体系，把 JVM 指标（堆、GC、线程）持续采集到 Prometheus + Grafana。</li></ul><h2 id="关键启动参数" tabindex="-1">关键启动参数 <a class="header-anchor" href="#关键启动参数" aria-label="Permalink to &quot;关键启动参数&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">-Xms2g</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -Xmx2g</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">                 # 初始/最大堆，生产建议设为相等避免动态扩容</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">-Xmn1g</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">                        # 新生代大小</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">-XX:MetaspaceSize</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">=256m</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">        # 元空间初始大小</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">-XX:+UseG1GC</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">                  # 使用 G1</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">-XX:+HeapDumpOnOutOfMemoryError</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">   # OOM 时自动转储</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">-XX:HeapDumpPath</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">=/path/heap.hprof</span></span></code></pre></div><h2 id="选型与实践建议" tabindex="-1">选型与实践建议 <a class="header-anchor" href="#选型与实践建议" aria-label="Permalink to &quot;选型与实践建议&quot;">​</a></h2><ul><li>容器化部署（Docker/K8s）务必用 JDK 10+ 的容器感知能力，或显式设置堆大小，避免 JVM 误读宿主机内存导致 OOM。</li><li><code>-Xms</code> 与 <code>-Xmx</code> 设为相等，避免运行期堆动态伸缩带来的停顿。</li><li>一定要开启 <code>HeapDumpOnOutOfMemoryError</code>，否则 OOM 现场难以复原。</li><li>JVM 指标纳入监控告警，不要等线上崩了才看。</li></ul>`,31)])])}const g=s(e,[["render",l]]);export{c as __pageData,g as default};
